  ('disabled-57f41407-moex-00279', 'disabled-57f41407', 'disabled-57f41407-moex-113-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '下列何者不得聲請法院依督促程序發支付命令？', '["本票執票人請求發票人給付票款", "公司員工請求任職之公司給付薪資", "名譽權受侵害之人請求加害人回復其名譽", "身體權受侵害之人請求加害人賠償其醫藥費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
